/* ========== 动画关键帧 ========== */
@keyframes fadeInUp {
  0% { opacity: 0; transform: translateY(20px); }
  100% { opacity: 1; transform: translateY(0); }
}

@keyframes floatBubble {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-4px); }
}

@keyframes pulseGlow {
  0% { box-shadow: 0 0 0 rgba(135, 206, 235, 0.5); }
  50% { box-shadow: 0 0 10px rgba(135, 206, 235, 0.8); }
  100% { box-shadow: 0 0 0 rgba(135, 206, 235, 0.5); }
}

@keyframes gradientFlow {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

/* ========== 聊天气泡美化 ========== */
.message {
  background: rgba(255, 255, 255, 0.6);
  border-radius: 16px;
  padding: 10px 14px;
  box-shadow: 0 4px 12px rgba(135, 206, 235, 0.4);
  animation: fadeInUp 0.4s ease both, floatBubble 4s ease-in-out infinite;
  backdrop-filter: blur(6px);
}

/* ========== 用户和AI消息分色 ========== */
.user .message {
  background: linear-gradient(135deg, rgba(200, 230, 255, 0.6), rgba(245, 255, 255, 0.6));
}

.bot .message {
  background: linear-gradient(135deg, rgba(220, 240, 255, 0.6), rgba(240, 255, 255, 0.6));
}

/* ========== 输入框 + 按钮动画 ========== */
input[type="text"]:focus, textarea:focus {
  border: 1px solid #87CEEB;
  animation: pulseGlow 1.5s infinite;
  outline: none;
}

button:hover {
  transform: scale(1.05);
  animation: pulseGlow 1.5s infinite;
  transition: all 0.3s ease;
}

/* ========== 渐变背景动画 ========== */
#chat {
  background: linear-gradient(270deg, #e0f7ff, #f0faff, #d6f0ff);
  background-size: 600% 600%;
  animation: gradientFlow 15s ease infinite;
  border-radius: 12px;
}

/* ========== 悬浮头像动画 ========== */
.avatar {
  animation: floatBubble 6s ease-in-out infinite;
  transition: transform 0.3s ease;
}

.avatar:hover {
  transform: scale(1.1);
}

/* ========== 滚动条美化 ========== */
::-webkit-scrollbar-thumb {
  background: linear-gradient(180deg, #cceeff, #aaddff);
  border-radius: 8px;
}

/* 保持原有字体和基础配色 */

/* ========== 动画关键帧 ========== */
@keyframes fadeInUp {
  0% {
    opacity: 0;
    transform: translateY(10px);
  }
