  color: #d6eaff !important;
  border: 1px solid rgba(255,255,255,0.15);
  border-radius: 10px;
  backdrop-filter: blur(8px);
  transition: box-shadow 0.3s ease, transform 0.3s ease;
}

pre:hover {
  box-shadow: 0 0 12px rgba(100,180,250,0.4);
  transform: translateY(-4px);
}

/* inline code 美化 */
code, [class*="hljs"] {
  color: #b6d9ff !important;
  background: rgba(30, 60, 90, 0.3) !important;
  border-radius: 4px;
  padding: 2px 6px;
}


/* ==========✨ 渐显动画 ========== */
